CREATE TABLE IF NOT EXISTS Medicines (
    id INT NOT NULL AUTO_INCREMENT,
    organization_id INT NOT NULL,
    medicine_code VARCHAR(30) NOT NULL,
    medicine_name VARCHAR(150) NOT NULL,
    generic_name VARCHAR(150) DEFAULT NULL,
    category VARCHAR(80) DEFAULT NULL,
    unit VARCHAR(30) DEFAULT NULL,
    strength VARCHAR(40) DEFAULT NULL,
    manufacturer VARCHAR(120) DEFAULT NULL,
    purchase_price DECIMAL(12,2) DEFAULT NULL,
    selling_price DECIMAL(12,2) DEFAULT NULL,
    stock_quantity INT DEFAULT NULL,
    reorder_level INT DEFAULT NULL,
    active BIT NOT NULL DEFAULT b'1',
    notes VARCHAR(500) DEFAULT NULL,
    created_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP,
    updated_at TIMESTAMP NOT NULL DEFAULT CURRENT_TIMESTAMP ON UPDATE CURRENT_TIMESTAMP,
    PRIMARY KEY (id),
    UNIQUE KEY uk_medicines_medicine_code (medicine_code),
    KEY idx_medicines_org (organization_id),
    CONSTRAINT fk_medicines_organization FOREIGN KEY (organization_id) REFERENCES Organizations(id)
);

-- Sample seed data for a single organization.
-- Replace organization_id = 1 if you want to target a different organization.
